import{_ as a,o as e,c as o,ag as n}from"./chunks/framework.OsDJF_Ea.js";const c=JSON.parse('{"title":"Banks and Controls","description":"","frontmatter":{},"headers":[],"relativePath":"guides/banks-and-controls.md","filePath":"guides/banks-and-controls.md"}'),s={name:"guides/banks-and-controls.md"};function l(d,t,r,i,h,u){return e(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="banks-and-controls" tabindex="-1">Banks and Controls <a class="header-anchor" href="#banks-and-controls" aria-label="Permalink to &quot;Banks and Controls&quot;">​</a></h1><p>The Smart Contact Mic has 4 physical pots and 4 buttons, but the banking system multiplies this to up to 24 pots and 24 buttons per patch.</p><h2 id="how-banks-work" tabindex="-1">How Banks Work <a class="header-anchor" href="#how-banks-work" aria-label="Permalink to &quot;How Banks Work&quot;">​</a></h2><p>The rotary encoder switches between 6 banks. Each bank assigns different functions to the same physical pots and buttons. The NeoPixel LEDs flash the bank colour when you switch:</p><table tabindex="0"><thead><tr><th>Bank</th><th>Colour</th><th>LED Feedback</th></tr></thead><tbody><tr><td>1</td><td>Red</td><td>Solid red flash</td></tr><tr><td>2</td><td>Green</td><td>Solid green flash</td></tr><tr><td>3</td><td>Blue</td><td>Solid blue flash</td></tr><tr><td>4</td><td>Yellow</td><td>Solid yellow flash</td></tr><tr><td>5</td><td>Cyan</td><td>Solid cyan flash</td></tr><tr><td>6</td><td>Magenta</td><td>Solid magenta flash</td></tr></tbody></table><h2 id="soft-takeover" tabindex="-1">Soft Takeover <a class="header-anchor" href="#soft-takeover" aria-label="Permalink to &quot;Soft Takeover&quot;">​</a></h2><p>When you switch banks, the pots don&#39;t jump to the stored values immediately. Instead:</p><ol><li>The pot output stays at the stored value for the new bank</li><li>You turn the physical pot toward the stored value</li><li>When the pot position comes within 5% of the target, control &quot;takes over&quot;</li><li>From that point, the pot tracks your physical movement normally</li></ol><p>This prevents sudden parameter jumps when switching banks.</p><h2 id="auto-mapped-modules" tabindex="-1">Auto-Mapped Modules <a class="header-anchor" href="#auto-mapped-modules" aria-label="Permalink to &quot;Auto-Mapped Modules&quot;">​</a></h2><p>Certain complex modules automatically claim banks and pre-assign the controls. When you add one of these modules, it takes the next available bank(s):</p><ul><li><strong>Stereo Mixer</strong> -- 1 or 2 banks (Volume/Mute + optional Pan/Solo)</li><li><strong>Drum Machine</strong> -- 2 banks (Trigger/Pitch + Volume/Mute)</li><li><strong>BPM Looper</strong> -- 2 banks (Record/Mix + Randomise/Pitch)</li></ul><p>These modules show a coloured footer on the canvas indicating their bank assignment.</p><h2 id="manual-pot-and-button-modules" tabindex="-1">Manual Pot and Button Modules <a class="header-anchor" href="#manual-pot-and-button-modules" aria-label="Permalink to &quot;Manual Pot and Button Modules&quot;">​</a></h2><p>When you add a Pot or Button module from the palette, it&#39;s assigned to the next free bank. If bank 1 and 2 are taken by a Drum Machine, your first Pot will go to bank 3.</p><p>You can see and change the bank assignment in the module&#39;s inspector panel.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Plan your bank layout before building complex patches. Put the most-used controls on bank 1.</li><li>Auto-mapped modules consume banks in order. Add them first, then fill remaining banks with manual controls.</li><li>The encoder button can have additional functions in some modules (like entering sub-menus on the Drum Machine).</li></ul>',18)])])}const m=a(s,[["render",l]]);export{c as __pageData,m as default};
